_requirements_text = NULL WHERE id = 'e0df88d7-93b0-4256-8983-5164389fecff';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Research Methodology","In addition to the thesis component, students will be required to take Research Methodology to enhance their knowledge in research.","Thesis","Students pursuing the PhD (Business) programme shall undertake an in-depth study on a particular research topic, the findings of which shall be submitted in the form of a thesis. The thesis must be defended in an oral examination, called  viva voce.","Areas of Research","We have a team of dedicated Supervisors with expertise in areas of research including (but not limited to):","Global Business","Transformative and/or digital Marketing","Energy and/or Green Finance","Sustainable Supply Chain Management","Digital Automation","Corporate Social Responsibility and/or ESG","Diversity and Inclusion","Modern workplace behaviour","Talent Management","Financial Reporting and Disclosure"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '6db2afc5-2d04-4994-b392-cad6bffe1adb';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Modules","Candidates are required to take three modules namely Research Methodology, Directed Readings and Research Proposal to enhance their knowledge in research, in addition to the thesis component.","Thesis","Areas of Research","Our researchers are highly accomplished, internationally recognised, and experienced with proven track records with expertise in areas of research including (but not limited to):","For other research areas, do write in to our contacts listed below.","Computer Networking","Information Systems","Human-Computer Interaction","Information Science","Image Processing","Artificial Intelligence","Machine Learning","Data Mining","Haptics","Software Engineering"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '033c70e2-39c5-4d8f-9894-05b82b2702fa';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Here’s the organized list of potential job roles in education administration and teaching:","Educational Administration and Teaching Career Prospects","Academician / Lecturer","School Principal","Head Faculty","School Director","Kindergarten Teacher","Teacher","Corporate Trainer","Year Level Coordinator","Student Engagement Lead","Student Experience Lead","Education Manager","Head of Department"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '51ac432e-a523-42f1-a6b4-49b8469adcb2';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Research Methodology","Thesis","PhD candidates will be empowered to complete an in-depth study on a particular research topic in the form of a thesis, substantiated by a series of academic milestones including a proposal defense and a viva voce, where the research outcomes ultimately contribute to the knowledge base of hospitality and tourism and its scholarly and professional communities.","Professional Development Activities","Additional required academic activities are regular consultations with the supervisory team, regular progress reports, participation in research seminars, the completion of a research ethics workshop and training programme, a conference presentation, and the submission of a manuscript to an academic journal.","Areas of Research","We have a team of dedicated Supervisors with expertise in areas of research including (but not limited to):","Hospitality and service management","Food, health, and well-being","Sustainability in tourism and the service industries","Events and destination management","Mobilities"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'd50326a8-8df9-43be-8917-15777a9af3ae';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Basic Medical Sciences","Applied Anatomy & Physiology","Behavioural Sciences","Concepts of Critical Care Nursing","Nursing Sciences","Cardiovascular and Blood Disorders Nursing","Respiratory Nursing","Neurological and Endocrine Nursing","Renal & Gastrointestinal Nursing","Trauma & Emergency Nursing","Clinical Placement","Clinical Placement - Professional and Practice","Note: All students are required to undergo ACLS during the programme"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '04928974-f559-430e-8a88-d6a0f4e9168b';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Modules","Candidates are required to take only one module namely Research Methodology to learn the techniques used to identify, select, process, and analyze information about a topic in research, in addition to the thesis component.","Thesis","Areas of Research","Our researchers are highly accomplished, internationally recognized, and experienced with proven track records with expertise in areas of research including (but not limited to):","For other research areas, do write in to our contacts listed below.","Renewable Energy Harvesting, Storage & Conversion","Heat Transfer Fluids and Nanofluids","Advanced & Emerging Nano-materials","Radiation interactions & applications","Applied Physics","CO2 Capture & Utilization","Green Technologies","Advanced water & waste water technology","Process Safety","Process Modeling and Simulations"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'b7c61d3b-4651-4a5d-82a8-51018dea45bb';
