UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["9 Modules and 1 Research Project","Marketing Innovation for Hospitality Business","Competitive Strategies for Hospitality Business","Research Methods for Hospitality and Tourism","Brand Management for Hospitality Business","Global Food Management","Leadership for Hospitality Business","Advanced Revenue Management","Contemporary Issues in Hospitality","Events Planning and Management","Hospitality Research Project","Areas of Research","Hospitality management","Hotel studies","Tourism and hospitality service marketing","Heritage and culture tourism","Tourism and hospitality human resources management","Branding and promotions in tourism and hospitality","Sustainability in tourism and hospitality","Culinary studies","Halal food studies","Halal food studies","Business travel and MICE","Green events","Communication in event studies"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '5f6e2bd7-40d1-4532-a88c-2c5ea9ce213f';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Clinical Research Methodology","This is a taught course and students are required to pass this module before the commencement of project. Students will have a designated supervisor who is a member of academic staff with research expertise in the student’s area of study.","Thesis","At the end of work completion, students are expected to submit their Master’s thesis for examination and attend a defence for their thesis.","Areas of Research","The School has a dedicated team of Supervisors with expertise in areas of research including (but not limited to):","Aging and Geriatrics","Cardiovascular Research","Communicable Diseases","Eco-health","Genomics and Precision Medicine","Neuroscience","Non-communicable Diseases","Oncology","Pharmacy","Public Health and Organisational Health"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'fb12bd6f-bb11-44f3-8a99-590067728f1f';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Structure","This programme is a 1-2 year programme of 8 modules including 4 core modules, 2 capstone research projects and 2 electives.","Core Modules","Microeconomics for Public Policy","Macroeconomics for Public Policy","Quantitative Research Methods","History of Economic Development","Available Electives","Financial Market DevelopmentInternational Trade, Regionalism and Global Value-Chains","Education Policies and Human Capital Development in Asia","Sustainable Development Policies","Urbanisation, Transportation and Regional Growth","Social Entrepreneurship and Inclusive Growth and more"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'fbae9938-2a3c-470b-ad92-4cc389327d3f';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Structure","Students are required to complete 6 core coursework modules, 2 Research Projects, and 2 Practicum courses.","Core Modules","Concepts and Principles of Behavioural Analysis","Measurement and Experimental Design","Identification and Assessment","Ethical and Professional Conduct","Behaviour Change Applications","Intervention and Implementation","Research Projects","Research Project 1","Research Project 2","Practicum","Students will complete two practical placements at agencies with onsite behaviour analyst supervisors overseeing their work in applying behavioural analytic concepts in the real world. These placements contribute to the professional training hours required by the Malaysia Association of Behaviour Analysis (MABA) to be a Malaysian Certified Behaviour Analyst (MCBA).","Practicum 1","Practicum 2"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '7cd667a5-2477-4aaf-8db6-4979695be362';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Structure","The programme is research-based culminating in a thesis (which may include a practical creative arts component, where applicable) that demonstrates mastery of the advanced points, craft and discipline of the area of research.","Module","The student is required to complete one taught module – Research Methods – before proceeding to the Proposal Defence. This core module introduces students to the fundamentals of academic research and methodologies at the postgraduate level to conduct an independent research project.","Class Schedule for Research Methods","This is an intensive course. Classes are spread over eight weeks (12 to 15 hours per week) for Full-time or Part-time students. These classes are followed by tutorials when the students conduct their research projects. Weekly schedules may vary from one year to another.","Thesis","During the course of their studies, the students will independently design and carry out an extensive research project with the assistance of the supervisor. The emphasis between theory and practice will vary according to the project. Students will develop significant research outcomes that are of national and international significance, and publicly disseminate these results to engage with the scholarly community.","Areas of Research","The school has a broad range of supervision expertise (not limited) to the following areas:","Digital Worlds and Media","Digital Humanities, VR, Digital Content Creation, Media Studies, Broadcasting, Social Media, New Media Creation.","Culture and Heritage","History of Cultures and Art, Crafts, Material Cultures, Music Traditions and Popular Music, Gender Studies, Southeast Asian Films, Sustainable Cultures, Eastern and Western Cultures.","Performance and Creation","Music and Theatre Performance, Graphic Design, Visual Arts, Fine Art.","Cities","History of the City and Urbanisation, Architecture, Cities in the South and Southeast Region, Cities in the West, Liveable Cities, Green Cities, Smart Cities, Touristic Cities."]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'c7fa79e9-98ab-4ad0-9da1-29852434c75a';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Structure","This programme is an MA by coursework. You will take six (6) core courses in research, media theory and media practise. From there you will chose two (2) electives in either theory, practise or both. The MA culminates in a Research-Creation Project as a final work. This project will utilise research methodologies in order to create unique visual works expressing the knowledge gained form your research.","The class structure of the programme is as follows:","Core Courses","Core Courses","Media Theory","Research Methods","Interactive Communications","Narratives in Media","Strategic Concept and Design","Professional Practise & Ethics","Electives (Choose 2)","Emerging Media","Technology, Development and Media","Brand Identity and Narrative","Research","Creation Project/Thesis"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '36be67ad-fde0-4c94-9688-38591e5047fe';
