UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Structure","Year 1 (Part & Full-Time: Compulsory)","Learning & Cognition","Measurement, Assessment, and Evaluation","AI in Education","Educational Research Methodology","Research Project 1 (Full-Time)","Research Project 2 (Full-Time)","Year 2 (Part-Time)","Research Project 1","Research Project 2","Elective Specialisations (Choose 1)","Instructional Technology","Design and Innovation in Sustainable Teaching and Learning","Digital and Expanding Literacies","Trends and Futures in Digital Learning*","Global Issues in Educational Technology*","Educational Management","Policy and Educational Planning","Human Resource Management in Education","Strategic Leadership in Education*","Global Issues and Sustainable Education*","Early Childhood Education","Theories and Practices in Early Childhood Education","Child Growth and Development","Inclusive Teaching & Learning*","Global Issues in Early Childhood Education*"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '82951348-1c40-48e3-a5d7-794b996fff31';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Research Methodology","In addition to the thesis component, students will be required to take Research Methodology to enhance their knowledge in research.","Thesis","Students pursuing the Master of Education programme shall undertake an in-depth study on a particular research topic, the findings of which shall be submitted in the form of a thesis. The thesis must be defended in an oral examination called viva voce.","Professional Development Activities","Workshops","To support our postgraduate students in their research journey, we provide a comprehensive and enriching learning experience through a strategic combination of workshop series and research colloquium. The workshop series aims to enhance practical research skills through hands-on sessions, fostering collaboration among students and addressing research challenges collectively. The tailored content delivery will cater specifically to the unique needs of educational research, covering areas such as skill acquisition, literature review techniques, methodologies, and ethical considerations. We also include a workshop on generative artificial intelligence (AI), equipping you with cutting-edge skills relevant to the demands of 21st-century teaching and learning.","There are nine (9) series of workshops that postgraduate students can attend before embarking on thesis writing. The first six (6) series of workshops are compulsory and the last three (3) series of workshops are optional.","Workshop 1: Introduction to Research Workshop 2: Reviewing the Literature Workshop 3: Research Purpose, Research Objectives, Research Questions and Hypotheses Workshop 4: Quantitative Research Methodology Workshop 5: Qualitative Research Methodology Workshop 6: Research Proposal and Thesis Writing Workshop 7: Generative AI for Research Workshop 8: SPSS for Beginners Workshop 9: NVivo for Beginners","Research Colloquium","Alongside a series of workshops, postgraduate students are encouraged to attend research colloquia, which offer opportunities for networking, presenting their work, and receiving constructive feedback from peers and faculty. This platform not only enhances presentation skills but also stimulates critical thinking by exposing students to a diverse range of research topics.","Areas of Research","We have a team of dedicated Supervisors with expertise in areas of research including (but not limited to):","Education Technology","Educational Psychology","Leadership & Management"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '2f0a4738-7a83-4407-ae73-1d567f8fb72f';
