UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Modules","For this PhD programme by Research, students are required to complete a Research Methods course.  This module introduces students to the academic research and methodologies at the postgraduate level in order to conduct an independent research study.","Thesis","Students must complete an in-depth research on a topic related to sustainable development in the form of a thesis. The student will be required to complete a number of academic milestones including a proposal defense and a viva voce.","Areas of Research","Economics and sustainable development","Education reform and social progress","Sustainable infrastructure, transportation and mobility","Urban sustainability","Corporate strategies and operations","Public policy and sustainable development","Solid and hazardous waste management","Political institutions, group conflicts, and democracy","Climate change adaptations","Renewable energy"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'a171ded7-e6ec-40ab-8da2-39219a8775fc';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Research Methodology","In addition to the thesis component, students will be required to take Research Methodology to enhance their knowledge in research.","Thesis","Students pursuing the Master of Philosophy (MPhil) programme shall undertake an in-depth study on a particular research topic, the findings of which shall be submitted in the form of a thesis. The thesis must be defended in an oral examination, called a viva voce.","Professional Development Activities","Candidates are also required to participate in academic activities, such as workshops, seminars, conferences and talks in various fields of study to enhance their knowledge, skills and experiences.","Areas of Research","We have a team of dedicated Supervisors with expertise in areas of research including (but not limited to):","Global Business","Transformative and/or digital Marketing","Energy and/or Green Finance","Sustainable Supply Chain Management","Digital Automation","Corporate Social Responsibility and/or ESG","Diversity and Inclusion","Modern workplace behaviour","Talent Management","Financial Reporting and Disclosure"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '0c8a40bb-44a8-4806-bf77-1cac234de8f4';
