UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Year 1 Modules","Research Methodology","Scientific Programming","Machine Learning","Predictive Models and Clustering Algorithms","Graphs and Networks","Optimization Techniques","Research Project 1","Research Project 2","Applied Combinatorics","Applied and Computational Dynamical Systems","Control Theory","Mathematical Modelling in Production Systems","Numerical Analysis with Applications","Optimal Control","Areas of Research","Big Data Analytics","Mathematical Modelling","Combinatorics","Computational Fluid Dynamics","Graph Theory","Multivariate Analysis","Neural Networks","Numerical Optimization","Optimal Control Computation","Optimal Control","Optimization","Simulation","Statistical Modelling","Statistical Quality Control","Time Series Modelling"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'c924f638-136b-4b34-a12d-613e59ca399a';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Research Methodology","Students will have an opportunity to examine research designs with methodology as well as data analysis techniques employed by researchers. At the end of this module, candidates will be expected to formulate and submit a proposal for research in an area of their own interest or specialisation.","Directed Readings","This module will provide students with comprehensive reading lists and resources to help them develop their hypothesis or areas of interest. Library skills and training on how to manage information and resources will also be introduced in this module.","Thesis","Areas of Research","Our academics have expertise in the following research areas ( But not limited to ):","For other research areas, do write in to our contacts listed below.","Artificial Intelligence (AI)","Embedded Systems/IoT","Cybersecurity & Blockchain","Robotics & Drones","Big Data & Data Analytics","Embedded Systems and Applications","Visual Sensor Network","Sensing & Signal Processing","Machine Learning & Human Factors","Power Systems"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'b555992d-7386-4bb0-b869-7cbe4c6f2161';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Research Methodology","Candidates will have an opportunity to examine research designs with methodology as well as data analysis techniques employed by Information Systems researchers. At the end of this module, candidates will be expected to formulate and submit a proposal for research in an area of their own interest or specialisation.","Directed Readings","This module will provide students with comprehensive reading lists and resources to help them develop research models and areas of interest. Literature review skills and training on how to manage information and resources will also be introduced in this module.","Thesis","Areas of Research","Our academics have expertise in the following research areas (but not limited to):","For other research areas, do write in to our contacts listed below","Artificial Intelligence (AI)","Embedded Systems/IoT","Cybersecurity & Blockchain","Robotics & Drones","Big Data & Data Analytics","Embedded Systems and Applications","Visual Sensor Network","Sensing & Signal Processing","Machine Learning & Human Factors","Power Systems"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'e93b484c-9b92-4569-99e3-5f110193cb96';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Modules","Candidates are required to complete two modules, namely Research Methodology and Directed Readings, in addition to the Thesis component. By undergoing these modules, candidates will develop the necessary skills and knowledge to conduct research successfully towards the completion of the thesis.","Thesis","Areas of Research","The School has a dedicated team of academicians who  will mentor and discuss possible research topics with  you in the following areas of research interests, but  not limited to:","Applied econometric","Big data analytics","Computational fluid dynamics","Evolutionary computation","Graph theory and combinatorics","Neural networks","Optimal control and numerical optimisation","Statistical modelling","Statistical process control","Time series analysis and forecasting"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'e190da93-1c9f-4249-8226-3f2fe4c9638b';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Programme Structure","Development across Lifespan","Theories and Process of Counselling","Foundation of Counselling Skills","Theories of Career Development","Career Counselling in Practice","Theories and Techniques of Group Counselling","Multicultural Counselling","Counselling Research Design & Statistics","Psychological Testing","Assessment in Counselling","Legal and Ethics in Counselling","Research Project","Electives","Pick 1 elective","Marital and Family Counselling","Tele-Mental Health Counselling","Entrepreneurship in Counselling","Crisis Intervention in Counselling","Children & Adolescent Mental Health","Clinical Mental Health Counselling","Psychopathology in Counselling"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'f66990af-33cc-4fa0-9d47-155de9657104';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Research Methodology","Students will learn about current approaches to research design, data analysis and scientific writing. At the end of this module, candidates will be expected to formulate and submit a proposal for research in an area of their interest or specialisation. Candidates will also develop the necessary skills and knowledge to conduct research  successfully.","Thesis","Areas of Research","The School has a dedicated team of Supervisors with expertise in areas of research including (but not limited to):","Antimicrobials","Bioinformatics","Cancer biology and therapeutics","Cell biology","Ecology and conservation","Infectious diseases","Microbiology","Molecular biology and genetics","Neurobiology","Neurodegenerative diseases","Virology"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '492869b1-d42c-4ec9-bb42-4c1bdf46b33a';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Module","The student is required to complete one taught module – Research Methods – before proceeding to the Proposal Defence. This core module introduces students to the fundamentals of academic research and methodologies at the postgraduate level to conduct an independent research project.","Class Schedule for Research Methods","This is an intensive course. Classes are spread over eight weeks (12 to 15 hours per week) for Full-time or Part-time students. These classes are followed by tutorials when the students conduct their research projects. Weekly schedules may vary from one year to another.","Thesis","During the course of their studies, the students will independently design and carry out an extensive research project with the assistance of the supervisor. The emphasis between theory and practice will vary according to the project. Students will develop significant research outcomes that are of national and international significance, and publicly disseminate these results to engage with the scholarly community.","Areas of Research","The school has a broad range of supervision expertise (not limited) to the following areas:","Digital Worlds and Media","Digital Humanities, VR, Digital Content Creation, Media Studies, Broadcasting, Social Media, New Media Creation.","Culture and Heritage","History of Cultures and Art, Crafts, Material Cultures, Music Traditions and Popular Music, Gender Studies, Southeast Asian Films, Sustainable Cultures, Eastern and Western Cultures.","Performance and Creation","Music and Theatre Performance, Graphic Design, Visual Arts, Fine Art.","Cities","History of the City and Urbanisation, Architecture, Cities in the South and Southeast Region, Cities in the West, Liveable Cities, Green Cities, Smart Cities, Touristic Cities."]}]'::jsonb, entry_requirements_text = NULL WHERE id = '83069d4f-662c-400c-883e-bff0f1349a25';
