UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["MODULES YOU STUDY","The studied modules assist in developing your study skills, introduce you to what to expect in your degree, and allow you to explore your study options based on your chosen path. This includes fields such as Accounting, Banking, Finance, Actuarial Studies, Psychology, Business & Management, Computing & Technology, Engineering, Industrial Design, Animation, and Visual Effects.","Semester 1 (12 weeks)","English for Academic Purpose","Communication Skills","Personal Development & Study Methods","Essentials of Web Applications","Mathematics","Note: This is a common Semester 1 across all pathways.","Semester 2 (12 weeks)","Fundamentals of Drawing","Life Drawing","Design Studies","Public Speaking in English","Major Project 1","Semester 3 (12 weeks)","Academic Research Skills","Introduction to Digital Photography","Major Project 2","Co-Curricular Studies","Choose one of the following modules:","History of Design and Media","Introduction to Architecture and Built Environment"]}]'::jsonb, entry_requirements_text = NULL WHERE id = 'cd4dc297-cca5-44d5-b0ba-98243bf88b35';
