UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Modules & Project Overview","This program comprises 13 coursework modules and a project. There are 10 compulsory core modules (including the Research Methodology module) and 3 specialization modules.","Pre-requisite Modules (for Non-Business Students)","Duration:","1 Month (Full-time)","2 Months (Part-time)","Managing People","Understanding Customers","Managerial Finance","Business Environment & Strategic Planning","Core Modules","Organisational Behaviour","Accounting & Finance for Managers","Managerial Economics","Technology Management","Global Strategic Management","Human Resource Management","Statistical Decision Making","Research Methodology","Entrepreneurship","Digital Marketing Tools and Trends","Project","A comprehensive project that integrates knowledge and skills acquired throughout the program.","Specialization Modules","Events Planning and Management","Leadership for Hospitality Business","Sustainable Tourism"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '59f77a15-fe55-4401-84fc-a067d149f1bf';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Conversion to PhD","Students enrolled in the Research Degree programme may convert to PhD candidacy if they meet all of the following criteria:","(a) Show excellent progress in their research.  (b) Demonstrate that their project can be expanded to PhD level.  (c) Pass a rigorous assessment.","Successful conversion changes the student’s status from Research Degree candidate to PhD candidate, with the candidature start date backdated to the original Research Degree registration date. This allows the student to obtain a PhD in a shorter timeframe without having to complete a separate Master’s programme.","Modules and Assessments","This programme is research-led and assessed through oral presentations and written reports at several stages, including: Proposal Defence, regular half-yearly progress reviews at research colloquia, Work Completion Defence, Thesis Examination, and Viva Voce. Students are required to complete one taught module in Research Methodology to acquire the prerequisite knowledge for effective research. Regular meetings with supervisors are expected to guide the research direction and to ensure the quality and significance of the findings."]}]'::jsonb, entry_requirements_text = NULL WHERE id = '7123fa97-8629-4fb2-96c1-f60ed1d755f3';
