UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Phase 1","Coursework (Two core courses)","Research Process and Academic Writing","Research Design and Methodology","The Colloquium Allows students to gain public speaking experience, learn about student research from fields within and outside their academic discipline, and experience judging methods used by professional panels for national and international meetings.","Phase 2","Proposal Defence","Each student must submit the first three chapters of his or her thesis for internal assessment. They must then present and defend their PhD","research proposal. The student is only allowed to continue with the research to Phase 3 on the passing of the defence of their proposal.","Phase 3","Data Collection and Thesis Preparation","The student proceeds to his/her data collection, data analysis and thesis writing","The Work Completion Seminar Serves as a moderation process to assess whether the work done by the candidate is sufficient for the PhD degree. The candidate must pass this before their thesis is allowed to proceed to Viva Voce.","Phase 4","Viva Voce","After submitting the thesis, the students is required to attend a Viva Voce to defend his/her thesis"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '4394d4e3-1a2c-427b-908d-e299f4825aeb';
UPDATE public.courses SET curriculum = '[{"year":"Core Subjects","modules":["Phase 1","Coursework (Three core courses)","Academic Writing","Research Methodologies","Communication Theories","The Colloquium","Allows students to gain public speaking experience, learn about student research from fields within and outside their academic discipline, and experience judging methods used by professional panels for national and international meetings.","Phase 2","Proposal Defence","Each student must submit the first three chapters of his or her thesis for internal assessment. They must then present and defend their PhD research proposal. The student is only allowed to continue with the research to Phase 3 on the passing of the defence of their proposal.","Phase 3","Data Collection and Thesis Preparation","The student proceeds to his/her data collection, data analysis and thesis writing","The Work Completion Seminar  Serves as a moderation process to assess whether the work done by the candidate is sufficient for the PhD degree. The candidate must pass this before their thesis is allowed to proceed to Viva Voce.","Phase 4","Viva Voce","After submitting the thesis, the students is required to attend a Viva Voce to defend his/her thesis"]}]'::jsonb, entry_requirements_text = NULL WHERE id = '84013075-79b0-4f3b-b9ff-76341be8f0ac';
